mapper.insert:
INSERT INTO tutor_message (
    id, booking_id, tutor_id, student_id, sender_role, content
) VALUES (
    UUID(), #{bookingId}, #{tutorId}, #{studentId}, #{senderRole}, #{content}
)

mapper.select:
SELECT COUNT(*)
FROM booking b
JOIN lesson l ON b.lesson_id = l.id
WHERE l.user_id = #{tutorId}
  AND b.user_id = #{studentId}
  AND b.id = #{bookingId}
  AND b.canceled_at IS NULL
